import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import certificatesData from '../data/certificate-data';
import CertificateGenerator from '../services/CertificateGenerator';

const CertificatesPage = () => {
  const { t, i18n } = useTranslation();
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCertificate, setSelectedCertificate] = useState(null);
  const [processedCertificates, setProcessedCertificates] = useState([]);
  const [isDownloading, setIsDownloading] = useState(false);
  const [downloadStatus, setDownloadStatus] = useState({ certificateId: null, status: null, message: '' });
  const currentLanguage = i18n.language;
  const isEnglish = currentLanguage === 'en' || currentLanguage.startsWith('en-');

  // 处理SVG证书
  useEffect(() => {
    // 为每个证书创建处理后的图像URL
    const processCertificates = async () => {
      // 显示加载状态
      const emptyProcessed = certificatesData.map(cert => ({
        ...cert,
        processedImage: null,
        isLoading: true
      }));
      setProcessedCertificates(emptyProcessed);
      
      const processed = await Promise.all(
        certificatesData.map(async (cert) => {
          try {
            // 获取SVG模板
            const response = await fetch(cert.image);
            if (!response.ok) throw new Error('Failed to load certificate template');
            
            let svgText = await response.text();
            
            // 对姓名和课程名称进行编码，防止XML注入和特殊字符问题
            const encodedName = cert.name.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
            const encodedCourse = (isEnglish && cert.english_course) 
              ? cert.english_course.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
              : cert.course.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
            const encodedDescription = (isEnglish && cert.english_description) ? cert.english_description : '';
            
            // 替换占位符
            svgText = svgText.replace(/\[RECIPIENT NAME\]/g, encodedName);
            svgText = svgText.replace(/\[DATE\]/g, cert.date);
            svgText = svgText.replace(/\[CERTIFICATE-ID\]/g, cert.certificateId);
            svgText = svgText.replace(/\[PROGRAM\/DEGREE\]/g, encodedCourse);
            svgText = svgText.replace(/\[PROGRAM_DESCRIPTION\]/g, encodedDescription);
            svgText = svgText.replace(/\[HASH\]/g, 'SIU-' + Math.random().toString(36).substring(2, 10).toUpperCase());
            
            // 创建Blob和URL
            const blob = new Blob([svgText], { type: 'image/svg+xml' });
            const url = URL.createObjectURL(blob);
            
            return { ...cert, processedImage: url, isLoading: false };
          } catch (error) {
            console.error('Error processing certificate:', error);
            return { ...cert, processedImage: cert.image, isLoading: false, error: true };
          }
        })
      );
      
      setProcessedCertificates(processed);
    };
    
    processCertificates();
    
    // 清理函数
    return () => {
      // 释放创建的对象URL
      processedCertificates.forEach(cert => {
        if (cert.processedImage && cert.processedImage.startsWith('blob:')) {
          URL.revokeObjectURL(cert.processedImage);
        }
      });
    };
  }, [isEnglish]);
  
  // 搜索筛选逻辑
  const filteredCertificates = processedCertificates.filter(cert =>
    cert.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (isEnglish && cert.english_course ? cert.english_course.toLowerCase().includes(searchTerm.toLowerCase()) : cert.course.toLowerCase().includes(searchTerm.toLowerCase())) ||
    cert.certificateId.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // 选择证书查看详情
  const handleCertificateClick = (certificate) => {
    setSelectedCertificate(certificate);
  };

  // 关闭证书详情模态框
  const closeModal = () => {
    setSelectedCertificate(null);
  };
  
  // 下载证书
  const downloadCertificate = async (certificate, e) => {
    e.stopPropagation(); // 防止触发模态框
    
    try {
      setIsDownloading(true);
      setDownloadStatus({
        certificateId: certificate.certificateId,
        status: 'downloading',
        message: t('certificatesPage.downloadingMessage')
      });
      
      const success = await CertificateGenerator.downloadCertificate(certificate);
      
      if (success) {
        setDownloadStatus({
          certificateId: certificate.certificateId,
          status: 'success',
          message: t('certificatesPage.downloadSuccess')
        });
        
        // 3秒后重置状态
        setTimeout(() => {
          setDownloadStatus({ certificateId: null, status: null, message: '' });
        }, 3000);
      } else {
        throw new Error('Download failed');
      }
    } catch (error) {
      console.error('Download error:', error);
      setDownloadStatus({
        certificateId: certificate.certificateId,
        status: 'error',
        message: t('certificatesPage.downloadError')
      });
      
      // 3秒后重置错误状态
      setTimeout(() => {
        setDownloadStatus({ certificateId: null, status: null, message: '' });
      }, 3000);
    } finally {
      setIsDownloading(false);
    }
  };
  
  // 格式化发布日期
  const formatDate = (dateString) => {
    const options = { year: 'numeric', month: 'long', day: 'numeric' };
    return new Date(dateString).toLocaleDateString(isEnglish ? 'en-US' : 'zh-CN', options);
  };

  // 根据当前语言获取课程名称
  const getCourseTitle = (certificate) => {
    return isEnglish && certificate.english_course 
      ? certificate.english_course 
      : certificate.course;
  };

  // 根据当前语言获取课程描述
  const getCourseDescription = (certificate) => {
    return isEnglish && certificate.english_description 
      ? certificate.english_description 
      : certificate.description;
  };

  return (
    <div className="bg-gray-50 min-h-screen py-12">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* 标题部分 */}
        <div className="text-center mb-12">
          <h1 className="text-3xl font-extrabold text-gray-900 sm:text-4xl">{t('certificatesPage.title')}</h1>
          <p className="mt-3 max-w-2xl mx-auto text-xl text-gray-500 sm:mt-4">
            {t('certificatesPage.subtitle')}
          </p>
        </div>

        {/* 搜索框 */}
        <div className="max-w-xl mx-auto mb-10">
          <div className="relative">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <svg className="h-5 w-5 text-gray-400" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
            </div>
            <input
              type="text"
              className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-md leading-5 bg-white shadow-sm focus:outline-none focus:ring-[#003087] focus:border-[#003087]"
              placeholder={t('certificatesPage.searchPlaceholder')}
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        {/* 证书展示区域 */}
        <div className="grid grid-cols-1 gap-8 sm:grid-cols-2 lg:grid-cols-3">
          {filteredCertificates.map((certificate) => (
            <div
              key={certificate.id}
              className="bg-white overflow-hidden shadow rounded-lg cursor-pointer transform transition duration-300 hover:shadow-lg hover:scale-105 text-left w-full border border-gray-200 focus:outline-none focus:ring-2 focus:ring-[#003087]"
            >
              {/* 证书卡片 */}
              <div className="relative">
                <button 
                  className="h-52 bg-gray-200 overflow-hidden relative w-full focus:outline-none" 
                  onClick={() => handleCertificateClick(certificate)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' || e.key === ' ') {
                      handleCertificateClick(certificate);
                    }
                  }}
                  aria-label={`查看${certificate.name}的${getCourseTitle(certificate)}证书详情`}
                >
                  {certificate.isLoading ? (
                    <div className="flex items-center justify-center h-full">
                      <svg className="animate-spin h-10 w-10 text-[#003087]" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                    </div>
                  ) : certificate.error ? (
                    <div className="flex items-center justify-center h-full bg-red-50">
                      <div className="text-center p-4">
                        <svg className="mx-auto h-12 w-12 text-red-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                        </svg>
                        <p className="mt-2 text-sm text-red-800">证书图像加载出错</p>
                      </div>
                    </div>
                  ) : (
                    <img
                      src={certificate.processedImage || certificate.image}
                      alt={`${certificate.name}的${getCourseTitle(certificate)}证书`}
                      className="w-full h-full object-contain"
                    />
                  )}
                </button>
                <div className="absolute top-2 right-2">
                  <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                    {certificate.certificateId}
                  </span>
                </div>
              </div>
              
              {/* 证书信息 */}
              <div className="px-4 py-4">
                <h3 className="text-lg font-medium text-gray-900">{certificate.name}</h3>
                <p className="text-md font-medium text-[#003087]">{getCourseTitle(certificate)}</p>
                <p className="mt-1 text-sm text-gray-500 line-clamp-2">{getCourseDescription(certificate)}</p>
                <p className="mt-2 text-xs text-gray-400">Issue Date: {formatDate(certificate.date)}</p>
                
                <div className="mt-4 flex">
                  <button
                    type="button"
                    className="inline-flex items-center px-3 py-2 border border-transparent text-sm leading-4 font-medium rounded-md shadow-sm text-white bg-[#003087] hover:bg-[#002266] focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-[#003087] transition-colors w-full justify-center"
                    onClick={(e) => downloadCertificate(certificate, e)}
                    disabled={isDownloading && downloadStatus.certificateId === certificate.certificateId}
                    aria-label={t('certificatesPage.ariaLabel', { name: certificate.name, course: getCourseTitle(certificate) })}
                  >
                    {isDownloading && downloadStatus.certificateId === certificate.certificateId ? (
                      <>
                        <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                        </svg>
                        {t('certificatesPage.downloading')}
                      </>
                    ) : (
                      <>
                        <svg className="-ml-0.5 mr-2 h-4 w-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                        </svg>
                        {t('certificatesPage.download')}
                      </>
                    )}
                  </button>
                </div>
                
                {/* 下载状态消息 */}
                {downloadStatus.certificateId === certificate.certificateId && downloadStatus.status && (
                  <div className={`mt-2 text-xs ${
                    downloadStatus.status === 'success' ? 'text-green-600' : 
                    downloadStatus.status === 'error' ? 'text-red-600' : 'text-blue-600'
                  }`}>
                    {downloadStatus.message}
                  </div>
                )}
              </div>
              
              {/* 认证标志 */}
              <div className="px-5 py-2 bg-gray-50 border-t border-gray-200 flex items-center">
                <svg className="h-4 w-4 text-[#D4A017] mr-1" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M6.267 3.455a3.066 3.066 0 001.745-.723 3.066 3.066 0 013.976 0 3.066 3.066 0 001.745.723 3.066 3.066 0 012.812 2.812c.051.643.304 1.254.723 1.745a3.066 3.066 0 010 3.976 3.066 3.066 0 00-.723 1.745 3.066 3.066 0 01-2.812 2.812 3.066 3.066 0 00-1.745.723 3.066 3.066 0 01-3.976 0 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-2.812-2.812 3.066 3.066 0 00-.723-1.745 3.066 3.066 0 010-3.976 3.066 3.066 0 00.723-1.745 3.066 3.066 0 012.812-2.812zm7.44 5.252a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                </svg>
                <span className="text-xs text-gray-500">
                  {t('Accredited by Global Academic Standards Board')}
                </span>
              </div>
            </div>
          ))}
        </div>

        {/* 无结果提示 */}
        {filteredCertificates.length === 0 && (
          <div className="text-center py-12">
            <svg className="mx-auto h-12 w-12 text-gray-400" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            <h3 className="mt-2 text-lg font-medium text-gray-900">{t('certificatesPage.noResultsTitle')}</h3>
            <p className="mt-1 text-sm text-gray-500">{t('certificatesPage.noResultsText')}</p>
          </div>
        )}

        {/* 验证证书区域 */}
        <div 
          className="mt-16 bg-gradient-to-r from-[#003087] to-[#004db3] rounded-lg shadow-lg overflow-hidden"
        >
          <div className="px-6 py-8 sm:p-10 sm:pb-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-center">
              <div>
                <h3 
                  className="text-2xl leading-8 font-extrabold text-white tracking-tight"
                >
                  {t('certificatesPage.verifySection.title')}
                </h3>
                <p 
                  className="mt-4 text-lg text-gray-100"
                >
                  {t('certificatesPage.verifySection.description')}
                </p>
                <div className="mt-6">
                  <Link
                    to="/verify-certificate"
                    className="inline-flex items-center px-6 py-3 border border-transparent text-base font-medium rounded-md shadow-sm text-[#003087] bg-white hover:bg-gray-50 transition-colors"
                  >
                    <svg className="mr-2 h-5 w-5 text-[#003087]" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                    </svg>
                    {t('certificatesPage.verifySection.action')}
                  </Link>
                </div>
              </div>
              <div className="hidden md:block">
                <img 
                  src="/images/certificates/certificate-verification.png" 
                  alt="Certificate verification" 
                  className="max-h-64 mx-auto"
                />
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* 证书详情模态框 */}
      {selectedCertificate && (
        <div className="fixed z-10 inset-0 overflow-y-auto" role="dialog" aria-modal="true">
          <div className="flex items-end justify-center min-h-screen pt-4 px-4 pb-20 text-center sm:block sm:p-0">
            <div className="fixed inset-0 bg-gray-500 bg-opacity-75 transition-opacity" aria-hidden="true" onClick={closeModal}></div>

            <span className="hidden sm:inline-block sm:align-middle sm:h-screen" aria-hidden="true">&#8203;</span>

            <div className="inline-block align-bottom bg-white rounded-lg text-left overflow-hidden shadow-xl transform transition-all sm:my-8 sm:align-middle sm:max-w-4xl sm:w-full">
              <div className="bg-white">
                <div className="relative">
                  {selectedCertificate.isLoading ? (
                    <div className="flex items-center justify-center h-64 bg-gray-100">
                      <svg className="animate-spin h-12 w-12 text-[#003087]" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                    </div>
                  ) : selectedCertificate.error ? (
                    <div className="flex items-center justify-center h-64 bg-red-50">
                      <div className="text-center p-4">
                        <svg className="mx-auto h-16 w-16 text-red-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                        </svg>
                        <p className="mt-4 text-lg text-red-800">证书图像加载失败</p>
                        <p className="mt-2 text-sm text-red-600">请稍后再试或联系管理员</p>
                      </div>
                    </div>
                  ) : (
                    <img
                      src={selectedCertificate.processedImage || selectedCertificate.image}
                      alt={`${selectedCertificate.name}的${getCourseTitle(selectedCertificate)}证书`}
                      className="w-full h-auto"
                    />
                  )}
                  <button
                    type="button"
                    className="absolute top-4 right-4 bg-white rounded-full p-1 shadow-md hover:bg-gray-100"
                    onClick={closeModal}
                    aria-label={t('certificatesPage.certificateModal.close')}
                  >
                    <svg className="h-6 w-6 text-gray-900" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                </div>
                <div className="p-6 bg-gray-50">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                      <h3 className="text-lg font-bold text-gray-900 border-b border-gray-200 pb-2 mb-3">
                        {t('certificatesPage.certificateModal.studentInfo')}
                      </h3>
                      <p className="mt-2 text-gray-600">{t('certificatesPage.certificateModal.name')}: <span className="font-medium text-gray-900">{selectedCertificate.name}</span></p>
                    </div>
                    <div>
                      <h3 className="text-lg font-bold text-gray-900 border-b border-gray-200 pb-2 mb-3">
                        {t('certificatesPage.certificateModal.certificateDetails')}
                      </h3>
                      <p className="mt-2 text-gray-600">{t('certificatesPage.certificateModal.course')}: <span className="font-medium text-gray-900">{getCourseTitle(selectedCertificate)}</span></p>
                      <p className="mt-2 text-gray-600">{t('certificatesPage.certificateModal.description')}: <span className="font-medium text-gray-900">{getCourseDescription(selectedCertificate)}</span></p>
                      <p className="mt-2 text-gray-600">{t('certificatesPage.certificateModal.issueDate')}: <span className="font-medium text-gray-900">{formatDate(selectedCertificate.date)}</span></p>
                      <p className="mt-2 text-gray-600">{t('certificatesPage.certificateModal.certificateId')}: <span className="font-medium text-[#003087]">{selectedCertificate.certificateId}</span></p>
                    </div>
                  </div>
                  <div className="mt-6 flex flex-wrap gap-4 border-t border-gray-200 pt-4">
                    <button
                      type="button"
                      className="inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-[#003087] hover:bg-[#002266] focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-[#003087]"
                      onClick={() => downloadCertificate(selectedCertificate, { stopPropagation: () => {} })}
                    >
                      <svg className="mr-2 h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                      </svg>
                      {t('certificatesPage.certificateModal.download')}
                    </button>
                    <Link
                      to={`/verify-certificate?id=${selectedCertificate.certificateId}`}
                      className="inline-flex items-center px-4 py-2 border border-gray-300 rounded-md shadow-sm text-sm font-medium text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-[#003087]"
                    >
                      <svg className="mr-2 h-5 w-5 text-[#D4A017]" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                      </svg>
                      {t('certificatesPage.certificateModal.verify')}
                    </Link>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CertificatesPage;
